#!/usr/bin/env node
import { parseArgs, readJson, writeText } from './lib.mjs'

const DEFAULT_CATALOG_IN = 'data/card-products/card-products.normalized.json'
const DEFAULT_RULES_IN = 'data/card-products/card-benefit-rules.json'
const DEFAULT_CATALOG_OUT = 'src/lib/cardProductCatalog.generated.js'
const DEFAULT_RULES_OUT = 'src/lib/cardBenefitRules.generated.js'

function generatedModule({ name, metaName, value, meta }) {
  return [
    '// Generated by tools/card-scraper/generate-card-catalog.mjs.',
    '// Do not edit by hand. Re-run the card scraper pipeline instead.',
    '',
    `export const ${metaName} = Object.freeze(${JSON.stringify(meta, null, 2)})`,
    '',
    `export const ${name} = Object.freeze(${JSON.stringify(value, null, 2)})`,
    '',
  ].join('\n')
}

async function main() {
  const args = parseArgs()
  const catalogInput = args.catalog || DEFAULT_CATALOG_IN
  const rulesInput = args.rules || DEFAULT_RULES_IN
  const catalogOutput = args['catalog-out'] || DEFAULT_CATALOG_OUT
  const rulesOutput = args['rules-out'] || DEFAULT_RULES_OUT
  const catalog = await readJson(catalogInput)
  const rules = await readJson(rulesInput)
  const generatedAt = new Date().toISOString()

  await writeText(
    catalogOutput,
    generatedModule({
      name: 'CARD_PRODUCT_CATALOG',
      metaName: 'CARD_PRODUCT_CATALOG_META',
      value: catalog.items || [],
      meta: {
        schemaVersion: catalog.schemaVersion || 1,
        generatedAt,
        source: catalog.source || 'card-gorilla',
        sourceSitemap: catalog.sourceSitemap || '',
        sourceScrapedAt: catalog.sourceScrapedAt || '',
        count: Array.isArray(catalog.items) ? catalog.items.length : 0,
      },
    })
  )

  await writeText(
    rulesOutput,
    generatedModule({
      name: 'CARD_BENEFIT_RULES',
      metaName: 'CARD_BENEFIT_RULES_META',
      value: rules.rules || [],
      meta: {
        schemaVersion: rules.schemaVersion || 1,
        generatedAt,
        source: rules.source || 'card-gorilla',
        sourceCatalogGeneratedAt: rules.sourceCatalogGeneratedAt || '',
        count: Array.isArray(rules.rules) ? rules.rules.length : 0,
      },
    })
  )

  console.log(`[card-generate] wrote ${catalogOutput}`)
  console.log(`[card-generate] wrote ${rulesOutput}`)
}

main().catch((error) => {
  console.error(error)
  process.exitCode = 1
})
